function toTelex(str) {
  const map = {
    'à':'af','á':'as','ả':'ar','ã':'ax','ạ':'aj',
    'â':'aa','ầ':'aaf','ấ':'aas','ẩ':'aar','ẫ':'aax','ậ':'aaj',
    'ă':'aw','ằ':'awf','ắ':'aws','ẳ':'awr','ẵ':'awx','ặ':'awj',
    'À':'Af','Á':'As','Ả':'Ar','Ã':'Ax','Ạ':'Aj',
    'Â':'Aa','Ầ':'Aaf','Ấ':'Aas','Ẩ':'Aar','Ẫ':'Aax','Ậ':'Aaj',
    'Ă':'Aw','Ằ':'Awf','Ắ':'Aws','Ẳ':'Awr','Ẵ':'Awx','Ặ':'Awj',
    'è':'ef','é':'es','ẻ':'er','ẽ':'ex','ẹ':'ej',
    'ê':'ee','ề':'eef','ế':'ees','ể':'eer','ễ':'eex','ệ':'eej',
    'È':'Ef','É':'Es','Ẻ':'Er','Ẽ':'Ex','Ẹ':'Ej',
    'Ê':'Ee','Ề':'Eef','Ế':'Ees','Ể':'Eer','Ễ':'Eex','Ệ':'Eej',
    'ì':'if','í':'is','ỉ':'ir','ĩ':'ix','ị':'ij',
    'Ì':'If','Í':'Is','Ỉ':'Ir','Ĩ':'Ix','Ị':'Ij',
    'ò':'of','ó':'os','ỏ':'or','õ':'ox','ọ':'oj',
    'ô':'oo','ồ':'oof','ố':'oos','ổ':'oor','ỗ':'oox','ộ':'ooj',
    'ơ':'ow','ờ':'owf','ớ':'ows','ở':'owr','ỡ':'owx','ợ':'owj',
    'Ò':'Of','Ó':'Os','Ỏ':'Or','Õ':'Ox','Ọ':'Oj',
    'Ô':'Oo','Ồ':'Oof','Ố':'Oos','Ổ':'Oor','Ỗ':'Oox','Ộ':'Ooj',
    'Ơ':'Ow','Ờ':'Owf','Ớ':'Ows','Ở':'Owr','Ỡ':'Owx','Ợ':'Owj',
    'ù':'uf','ú':'us','ủ':'ur','ũ':'ux','ụ':'uj',
    'ư':'uw','ừ':'uwf','ứ':'uws','ử':'uwr','ữ':'uwx','ự':'uwj',
    'Ù':'Uf','Ú':'Us','Ủ':'Ur','Ũ':'Ux','Ụ':'Uj',
    'Ư':'Uw','Ừ':'Uwf','Ứ':'Uws','Ử':'Uwr','Ữ':'Uwx','Ự':'Uwj',
    'ỳ':'yf','ý':'ys','ỷ':'yr','ỹ':'yx','ỵ':'yj',
    'Ỳ':'Yf','Ý':'Ys','Ỷ':'Yr','Ỹ':'Yx','Ỵ':'Yj',
    'đ':'dd','Đ':'Dd'
  };

  return str.split('').map(ch => map[ch] || ch).join('');
}

function isNumeric(str) {
  return /^[0-9]+$/.test(str);
}

function convertDate(date) {
  if (date.split('/').length == 3) {
    const [day, month, year] = date.split("/").map(Number);
    return new Date(year, month - 1, day);
  }
  return new Date(date)
}

function convertVNDate(date) {
  let ngay = date.getDate()
  if (ngay < 10) {
    ngay = '0' + ngay
  }
  let thang = date.getMonth() + 1
  if (thang < 10) {
    thang = '0' + thang
  }
  let nam = date.getFullYear()
  return ngay + '/' + thang + '/' + nam
}
const objArr = []
for (const item of $input.all()) {
  let output = item.json.output[0].content[0].text
  console.log(output)
  if (output.length == 0) {
    objArr.push({})
    continue
  }
  const output2 = output.match(/\{[\s\S]*\}/);
  if (!output2) {
    objArr.push({})
    continue
  }
  const result = JSON.parse(output2[0])
  if (!result.type || !result.given_names) {
    objArr.push({})
    continue
  }

  const vnList = ['VN', 'VNM', 'VIETNAM', 'VIET NAM']
  if (!vnList.includes(result.issuing_country.toUpperCase())) {
    if (!result.type || !result.given_names) {
      objArr.push({})
      continue
    }
  }

  result['date_of_birth'] = convertDate(result['date_of_birth'])
  result['date_of_issue'] = convertDate(result['date_of_issue'])
  result['date_of_expiration'] = convertDate(result['date_of_expiration'])

  result['ngay_sinh'] = result['date_of_birth'].getDate()
  if (result['ngay_sinh'] < 10) {
    result['ngay_sinh'] = '0' + result['ngay_sinh']
  }
  result['thang_sinh'] = result['date_of_birth'].getMonth() + 1
  if (result['thang_sinh'] < 10) {
    result['thang_sinh'] = '0' + result['thang_sinh']
  }
  result['nam_sinh'] = result['date_of_birth'].getFullYear()

  result['ngay_cap'] = result['date_of_issue'].getDate()
  if (result['ngay_cap'] < 10) {
    result['ngay_cap'] = '0' + result['ngay_cap']
  }
  result['thang_cap'] = result['date_of_issue'].getMonth() + 1
  if (result['thang_cap'] < 10) {
    result['thang_cap'] = '0' + result['thang_cap']
  }
  result['nam_cap'] = result['date_of_issue'].getFullYear()

  result['ngay_thang_nam_sinh'] = convertVNDate(result['date_of_birth'])
  result['ngay_thang_nam_het_han'] = convertVNDate(result['date_of_expiration'])
  result['ngay_thang_nam_cap'] = convertVNDate(result['date_of_issue'])
  result['passport_number'] = result['passport_no']
  result['issue_date'] = result['ngay_thang_nam_cap']
  result['expiry_date'] = result['ngay_thang_nam_het_han']
  result['issuing_place'] = toTelex(result['issuing_authority'])
  result['birth_date'] = result['ngay_thang_nam_sinh']
  result['birth_place'] = result['place_of_birth']
  result['domestic_address'] = toTelex(result['place_of_birth'])
  result['overseas_address'] = ''
  result['original_nationality'] = 'Viet Nam'
  result['occupation'] = ''
  if (result['sex'] == 'M') {
    result['sex'] = 'Male'
  }
  if (result['sex'] == 'F') {
    result['sex'] = 'Female'
  }

  result['sex2'] = result['sex'].toLowerCase()
  result['fullname'] = result['surname'] + ' ' + result['given_names']
  result['surname_only'] = result['surname']
  result['fullname_telex'] = toTelex(result['fullname'])
  if (!isNumeric(result['cmnd'])) {
    result['cmnd'] = ''
  }
  result['passport_status'] = 'Valid'
  if (result['date_of_expiration'] < new Date()) {
    result['passport_status'] = 'Expired'
  }
  let nextYear = new Date();
  nextYear.setFullYear(nextYear.getFullYear() + 1);

  if (result['date_of_expiration'] > nextYear) {
    result['passport_status'] = 'Lost'
  }
  objArr.push({
    json: result
  })
}
return objArr

