return output;

const tab = String.fromCharCode(9);
const input = $input.first().json
let qr = `${input['passport_number']}${tab}${tab}${input['issue_date']}${tab}${input['expiry_date']}${tab}${tab}${tab}${input['issuing_place']}${tab}${input['fullname_telex']}${tab}${input['birth_date']}${tab}${tab}${input['sex']}${tab}${input['cmnd']}${tab}${input['birth_place']}${tab}${tab}${tab}${tab}${input['domestic_address']}${tab}${input['overseas_address']}`
let url = `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent(qr)}`
return { url, name: input['fullname'] }
